import (
	context "context"
	fernclient "github.com/schemaless-request-body-examples/fern/client"
)

client := fernclient.NewClient()
response, err := client.CreatePlant(
	context.TODO(),
	map[string]interface{}{
		"care": map[string]interface{}{
			"humidity": "high",
			"light":    "full sun",
			"water":    "distilled only",
		},
		"name":    "Venus Flytrap",
		"species": "Dionaea muscipula",
		"tags": []interface{}{
			"carnivorous",
			"tropical",
		},
	},
)

import (
	context "context"
	fern "github.com/schemaless-request-body-examples/fern"
	fernclient "github.com/schemaless-request-body-examples/fern/client"
)

client := fernclient.NewClient()
response, err := client.CreatePlantWithSchema(
	context.TODO(),
	&fern.CreatePlantWithSchemaRequest{
		Name: fern.String(
			"Sundew",
		),
		Species: fern.String(
			"Drosera capensis",
		),
	},
)

import (
	context "context"
	fern "github.com/schemaless-request-body-examples/fern"
	fernclient "github.com/schemaless-request-body-examples/fern/client"
)

client := fernclient.NewClient()
response, err := client.UpdatePlant(
	context.TODO(),
	&fern.UpdatePlantRequest{
		PlantID: "plantId",
		Body: map[string]interface{}{
			"care": map[string]interface{}{
				"light": "partial shade",
			},
			"name": "Updated Venus Flytrap",
		},
	},
)
